/// Build a bytes input with a MIME type and optional filename hint.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_extract_input_bytes(
    bytes: *const u8,
    bytes_len: usize,
    mime_type: *const std::ffi::c_char,
    filename: *const std::ffi::c_char,
) -> *mut xberg::ExtractInput {
    clear_last_error();
    if bytes.is_null() && bytes_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'bytes'");
        return std::ptr::null_mut();
    }
    // SAFETY: when bytes is null, bytes_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let bytes_rs = if bytes.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(bytes, bytes_len) }.to_vec()
    };
    if mime_type.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'mime_type'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees mime_type is a valid pointer; string is valid UTF-8 from caller.
    let mime_type_rs = match unsafe { CStr::from_ptr(mime_type) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'mime_type'");
            return std::ptr::null_mut();
        }
    };
    let filename_rs = if filename.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees filename is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(filename) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'filename'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = xberg::ExtractInput::bytes(bytes_rs, mime_type_rs, filename_rs);
    Box::into_raw(Box::new(result))
}

