/// Build `ConfidenceSignals` from an `ExtractionResult`.
///
/// * `result` â The extraction result whose `ocr_elements` are inspected.
/// * `schema_compliance` â Caller-supplied schema validation outcome.
/// * `text_coverage` â Caller-supplied fraction of pages with usable text
///   (e.g. 1.0 for native text formats, value from PDF analysis for PDFs).
///
/// The `ocr_aggregate` is computed as the arithmetic mean of all
/// `ocr_elements[].confidence.recognition` values.  When `ocr_elements` is
/// `None` or empty the field is set to `None`.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[cfg(feature = "heuristics")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_confidence_signals_from_extraction_result(
    result: *const xberg::ExtractionResult,
    schema_compliance: i32,
    text_coverage: f32,
) -> *mut xberg::ConfidenceSignals {
    clear_last_error();
    if result.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'result'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees result is a valid non-null pointer.
    let result_rs = unsafe { &*result };
    let schema_compliance_rs = match schema_compliance_from_i32_rs(schema_compliance) {
        Some(v) => v,
        None => {
            set_last_error(1, "invalid enum discriminant for SchemaCompliance");
            return std::ptr::null_mut();
        }
    };
    let text_coverage_rs = text_coverage;
    let result = xberg::ConfidenceSignals::from_extraction_result(&result_rs, schema_compliance_rs, text_coverage_rs);
    Box::into_raw(Box::new(result))
}

