/// Validate `raw` against the meta-schema and deserialize into a `Preset`,
/// stamping the fingerprint over the canonical file bytes.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[cfg(feature = "presets")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_meta_schema_parse_preset(
    this: *const xberg::MetaSchema,
    path: *const std::ffi::c_char,
    raw: *const u8,
    raw_len: usize,
) -> *mut xberg::Preset {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };

    if path.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'path'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees path is a valid pointer; string is valid UTF-8 from caller.
    let path_rs = match unsafe { CStr::from_ptr(path) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'path'");
            return std::ptr::null_mut();
        }
    };
    if raw.is_null() && raw_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'raw'");
        return std::ptr::null_mut();
    }
    // SAFETY: when raw is null, raw_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let raw_rs = if raw.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(raw, raw_len) }.to_vec()
    };
    let result = obj.parse_preset(&path_rs, &raw_rs);
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

