/// Load additional preset files from a runtime directory and insert them
/// into this registry.
///
/// Reads every `*.json` file directly under `dir` (non-recursive),
/// validates each against the meta-schema, and inserts it. Files that fail
/// validation are rejected â the error is returned immediately and the
/// registry is left in a partially-updated state. Existing entries with the
/// same id are overwritten.
///
/// Returns the number of presets successfully loaded from `dir`.
///
/// # Use case
///
/// This is the injection point for downstream catalogs that add curated
/// presets on top of the single embedded OSS preset.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[cfg(feature = "presets")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_registry_extend_from_dir(
    this: *mut xberg::Registry,
    dir: *const std::ffi::c_char,
) -> usize {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return 0;
    }
    // SAFETY: null check above guarantees this is a valid pointer; caller ensures exclusive access.
    let obj = unsafe { &mut *this };

    if dir.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'dir'");
        return 0;
    }
    // SAFETY: null check above guarantees dir is a valid pointer; string is valid UTF-8 from caller.
    let dir_rs = match unsafe { CStr::from_ptr(dir) }.to_str() {
        Ok(s) => std::path::PathBuf::from(s),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'dir'");
            return 0;
        }
    };
    let result = obj.extend_from_dir(dir_rs.as_path());
    match result {
        Ok(val) => val,
        Err(e) => {
            set_last_error(2, &e.to_string());
            0
        }
    }
}

