/// Render a heap-allocated `LayoutClass` as its string representation
/// (the unit-variant name as serialized by serde — e.g. `"completed"`,
/// without surrounding JSON quotes).
/// # Safety
/// `ptr` must be a valid, non-null pointer returned by a `xberg` function.
/// The returned string must be freed with `xberg_free_string`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_layout_class_to_string(ptr: *const xberg::LayoutClass) -> *mut c_char {
    if ptr.is_null() {
        set_last_error(1, "Null pointer passed to xberg_layout_class_to_string");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees ptr is valid; no mutable aliases held.
    let val = unsafe { &*ptr };
    let s: String = serde_json::to_value(val)
        .ok()
        .and_then(|v| v.as_str().map(str::to_owned))
        .unwrap_or_default();
    match CString::new(s) {
        Ok(cs) => cs.into_raw(),
        Err(_) => {
            set_last_error(1, "LayoutClass variant contained interior NUL byte");
            std::ptr::null_mut()
        }
    }
}

fn get_ffi_runtime() -> &'static tokio::runtime::Runtime {
    use std::sync::OnceLock;
    static RUNTIME: OnceLock<tokio::runtime::Runtime> = OnceLock::new();
    RUNTIME.get_or_init(|| tokio::runtime::Runtime::new().expect("Failed to create tokio runtime"))
}

/// Extract content from a single bytes or URI input.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_extract(
    input: *const xberg::ExtractInput,
    config: *const xberg::ExtractionConfig,
) -> *mut xberg::ExtractionOutput {
    clear_last_error();
    if input.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'input'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees input is a valid non-null pointer.
    let input_rs = unsafe { &*input }.clone();
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees config is a valid non-null pointer.
    let config_rs = unsafe { &*config };
    let result = get_ffi_runtime().block_on(async { xberg::extract(input_rs, &config_rs).await });
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Extract content from multiple bytes or URI inputs.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_extract_batch(
    inputs: *const std::ffi::c_char,
    config: *const xberg::ExtractionConfig,
) -> *mut xberg::ExtractionOutput {
    clear_last_error();
    if inputs.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'inputs'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees inputs is a valid pointer; string is valid UTF-8 from caller.
    let inputs_rs_str = match unsafe { CStr::from_ptr(inputs) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'inputs'");
            return std::ptr::null_mut();
        }
    };
    let inputs_rs = match serde_json::from_str::<Vec<xberg::ExtractInput>>(inputs_rs_str) {
        Ok(v) => v,
        Err(e) => {
            set_last_error(2, &e.to_string());
            return std::ptr::null_mut();
        }
    };
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees config is a valid non-null pointer.
    let config_rs = unsafe { &*config };
    let result = get_ffi_runtime().block_on(async { xberg::extract_batch(inputs_rs, &config_rs).await });
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Detect MIME type from raw file bytes.
///
/// Uses magic byte signatures to detect file type from content.
/// Falls back to `infer` crate for comprehensive detection.
///
/// For ZIP-based files, inspects contents to distinguish Office Open XML
/// formats (DOCX, XLSX, PPTX) from plain ZIP archives.
/// \param content Raw file bytes
/// \return The detected MIME type string.
/// \note Returns `XbergError::UnsupportedFormat` if MIME type cannot be determined.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_detect_mime_type_from_bytes(
    content: *const u8,
    content_len: usize,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if content.is_null() && content_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'content'");
        return std::ptr::null_mut();
    }
    // SAFETY: when content is null, content_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let content_rs = if content.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(content, content_len) }.to_vec()
    };
    let result = xberg::detect_mime_type_from_bytes(&content_rs);
    match result {
        Ok(val) => {
            let __alef_return = val.to_string();
            match CString::new(__alef_return) {
                Ok(cs) => {
                    set_last_return_len(cs.as_bytes().len());
                    cs.into_raw()
                }
                Err(_) => {
                    set_last_return_len(0);
                    std::ptr::null_mut()
                }
            }
        }
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

