/// Detect QR codes in the bytes of an `ExtractedImage`.
///
/// `format_hint` is currently unused â the `image` crate auto-detects the
/// container format from magic bytes â but the parameter is retained so future
/// backends (e.g. a WebP-via-`webp-decoder` variant) can use it without an API
/// break.
///
/// Returns an empty vector on any of:
///
/// - Empty input.
/// - Image-decode failure.
/// - No QR grids detected.
/// - All detected grids fail to decode.
///
/// Successfully decoded QR codes carry their payload, a confidence of `1.0`
/// (rqrr does not expose per-grid confidence; a successful decode is treated
/// as high-confidence by convention), and the pixel-space bounding box derived
/// from the four corner points of the grid.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_detect_qr_codes(
    image_bytes: *const u8,
    image_bytes_len: usize,
    _format_hint: *const std::ffi::c_char,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if image_bytes.is_null() && image_bytes_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'image_bytes'");
        return std::ptr::null_mut();
    }
    // SAFETY: when image_bytes is null, image_bytes_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let image_bytes_rs = if image_bytes.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(image_bytes, image_bytes_len) }.to_vec()
    };
    let _format_hint_rs = if _format_hint.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees _format_hint is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(_format_hint) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter '_format_hint'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = xberg::extractors::qr::detect_qr_codes(&image_bytes_rs, _format_hint_rs.as_deref());
    {
        match serde_json::to_string(&result) {
            Ok(__alef_return) => match CString::new(__alef_return) {
                Ok(cs) => {
                    set_last_return_len(cs.as_bytes().len());
                    cs.into_raw()
                }
                Err(_) => {
                    set_last_return_len(0);
                    std::ptr::null_mut()
                }
            },
            Err(_) => {
                set_last_return_len(0);
                std::ptr::null_mut()
            }
        }
    }
}

