/// Verify that an excerpt appears verbatim in source text.
///
/// Performs exact matching by default. Also tries whitespace-normalized matching
/// (collapsing runs of whitespace on both sides) since PDF-extracted text often
/// has irregular spacing.
/// \param excerpt The text snippet to find
/// \param source_text The full source text to search
/// \return `true` if the excerpt appears (exactly or with normalized whitespace), `false` otherwise.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
/// \code
/// let source = "The document states: Exact quoted text.";
/// let excerpt = "Exact quoted text";
/// assert!(verify_excerpt(excerpt, source));
///
/// // Whitespace normalization
/// let source2 = "Text with  irregular   spacing.";
/// let excerpt2 = "Text with irregular spacing";
/// assert!(verify_excerpt(excerpt2, source2));
/// \endcode
#[cfg(feature = "markdown-footnotes")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_verify_excerpt(
    excerpt: *const std::ffi::c_char,
    source_text: *const std::ffi::c_char,
) -> i32 {
    clear_last_error();
    if excerpt.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'excerpt'");
        return 0;
    }
    // SAFETY: null check above guarantees excerpt is a valid pointer; string is valid UTF-8 from caller.
    let excerpt_rs = match unsafe { CStr::from_ptr(excerpt) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'excerpt'");
            return 0;
        }
    };
    if source_text.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'source_text'");
        return 0;
    }
    // SAFETY: null check above guarantees source_text is a valid pointer; string is valid UTF-8 from caller.
    let source_text_rs = match unsafe { CStr::from_ptr(source_text) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'source_text'");
            return 0;
        }
    };
    let result = xberg::verify_excerpt(&excerpt_rs, &source_text_rs);
    if result {
        1
    } else {
        0
    }
}

