/// Compare two extraction results and return a structured diff.
///
/// The comparison is purely structural â no I/O, no side effects. All fields
/// of `ExtractionDiff` are populated according to the provided `DiffOptions`.
/// \param a â the "before" extraction result
/// \param b â the "after" extraction result
/// \param opts â controls which sections are compared and optional truncation
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
/// \code
/// use xberg::{ExtractionResult, diff::{compare, DiffOptions}};
///
/// let mut a = ExtractionResult::default();
/// let mut b = ExtractionResult::default();
/// a.content = "Hello world".to_string();
/// b.content = "Hello Rust".to_string();
///
/// let diff = compare(&a, &b, &DiffOptions::default());
/// assert_eq!(diff.content_diff.len(), 1);
/// \endcode
#[cfg(feature = "diff")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_compare(
    a: *const xberg::ExtractionResult,
    b: *const xberg::ExtractionResult,
    opts: *const xberg::DiffOptions,
) -> *mut xberg::ExtractionDiff {
    clear_last_error();
    if a.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'a'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees a is a valid non-null pointer.
    let a_rs = unsafe { &*a };
    if b.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'b'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees b is a valid non-null pointer.
    let b_rs = unsafe { &*b };
    if opts.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'opts'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees opts is a valid non-null pointer.
    let opts_rs = unsafe { &*opts };
    let result = xberg::compare(&a_rs, &b_rs, &opts_rs);
    Box::into_raw(Box::new(result))
}

/// Extract content from a pre-cropped image region using a VLM.
///
/// The caller is responsible for cropping the page image to the region's bounding
/// box before calling this function. The `image_bytes` parameter must contain the
/// raw bytes of the **cropped** region image (JPEG, PNG, WebP, etc.).
/// \param image_bytes â Raw bytes of the **pre-cropped** region image.
/// \param image_mime â MIME type of the image (`"image/png"`, `"image/jpeg"`, etc.).
/// \param region_kind â Content type of the region, used to select the default prompt.
/// \param llm_config â LLM provider and model configuration.
/// \param custom_prompt â Optional override for the default per-region prompt template.
/// \return Extracted Markdown text from the VLM, or an error if the VLM call fails.
/// \note - `Ocr` if the VLM call fails or returns no content.
/// - `MissingDependency` if the liter-llm client cannot
///   be initialised.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
/// \code
/// use xberg::llm::region_extractor::{RegionKind, extract_region_with_vlm};
/// use xberg::LlmConfig;
///
/// let image_bytes: Vec<u8> = std::fs::read("cropped_figure.png")?;
/// let config = LlmConfig {
///     model: "openai/gpt-4o-mini".to_string(),
///     base_url: Some("http://localhost:9999".to_string()),
///     ..Default::default()
/// };
/// let markdown = extract_region_with_vlm(
///     &image_bytes,
///     "image/png",
///     RegionKind::Figure,
///     &config,
///     None,
/// )
/// .await?;
/// println!("Extracted: {markdown}");
/// \endcode
#[cfg(all(feature = "liter-llm", not(target_arch = "wasm32")))]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_extract_region_with_vlm(
    image_bytes: *const u8,
    image_bytes_len: usize,
    image_mime: *const std::ffi::c_char,
    region_kind: i32,
    llm_config: *const xberg::LlmConfig,
    custom_prompt: *const std::ffi::c_char,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if image_bytes.is_null() && image_bytes_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'image_bytes'");
        return std::ptr::null_mut();
    }
    // SAFETY: when image_bytes is null, image_bytes_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let image_bytes_rs = if image_bytes.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(image_bytes, image_bytes_len) }.to_vec()
    };
    if image_mime.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'image_mime'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees image_mime is a valid pointer; string is valid UTF-8 from caller.
    let image_mime_rs = match unsafe { CStr::from_ptr(image_mime) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'image_mime'");
            return std::ptr::null_mut();
        }
    };
    let region_kind_rs = match region_kind_from_i32_rs(region_kind) {
        Some(v) => v,
        None => {
            set_last_error(1, "invalid enum discriminant for RegionKind");
            return std::ptr::null_mut();
        }
    };
    if llm_config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'llm_config'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees llm_config is a valid non-null pointer.
    let llm_config_rs = unsafe { &*llm_config };
    let custom_prompt_rs = if custom_prompt.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees custom_prompt is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(custom_prompt) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'custom_prompt'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = get_ffi_runtime().block_on(async {
        xberg::llm::region_extractor::extract_region_with_vlm(
            &image_bytes_rs,
            &image_mime_rs,
            region_kind_rs,
            &llm_config_rs,
            custom_prompt_rs.as_deref(),
        )
        .await
    });
    match result {
        Ok(val) => {
            let __alef_return = val.to_string();
            match CString::new(__alef_return) {
                Ok(cs) => {
                    set_last_return_len(cs.as_bytes().len());
                    cs.into_raw()
                }
                Err(_) => {
                    set_last_return_len(0);
                    std::ptr::null_mut()
                }
            }
        }
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

