/// Analyze a document and determine the optimal chunking strategy.
///
/// Decision logic (in priority order):
///
/// 1. If user provides `disable_chunking` â no chunking
/// 2. If user provides page_ranges â use user overrides
/// 3. If chunking is not enabled â no chunking
/// 4. If format doesn't support chunking â no chunking
/// 5. If file is small (below both thresholds) and not force_chunking â no chunking
/// 6. If PDF has a substantial text layer AND !force_ocr â no chunking
///    *(only when `heuristics-pdf` feature is enabled; otherwise skipped)*
/// 7. Otherwise â chunk the document
/// \note Returns an error only when the `heuristics-pdf` feature is active and
/// the PDF text-layer analysis itself returns a hard error.  In all other
/// cases the function returns a `ChunkingDecision`.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[cfg(feature = "heuristics")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_analyze_document(
    metadata: *const xberg::DocumentMetadata,
    config: *const xberg::HeuristicsConfig,
    document_bytes: *const u8,
    document_bytes_len: usize,
) -> *mut xberg::ChunkingDecision {
    clear_last_error();
    if metadata.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'metadata'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees metadata is a valid non-null pointer.
    let metadata_rs = unsafe { &*metadata };
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees config is a valid non-null pointer.
    let config_rs = unsafe { &*config };
    if document_bytes.is_null() && document_bytes_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'document_bytes'");
        return std::ptr::null_mut();
    }
    // SAFETY: a null document_bytes maps to None; otherwise the pointer is valid for document_bytes_len bytes.
    let document_bytes_rs = if document_bytes.is_null() {
        None
    } else {
        Some(unsafe { std::slice::from_raw_parts(document_bytes, document_bytes_len) }.to_vec())
    };
    let result = xberg::analyze_document(&metadata_rs, &config_rs, document_bytes_rs.as_deref());
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

