/// Resolve `(preset, custom_schema_override, context)` into a `ResolvedPreset`.
///
/// - `custom_schema` overrides `preset.schema` when set.
/// - `context` substitutes `{{key}}` tokens in `preset.context_template`; the
///   rendered string is appended to `system_prompt` so the model sees it.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[cfg(feature = "presets")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_resolve(
    preset: *const xberg::Preset,
    custom_schema: *const std::ffi::c_char,
    context: *const std::ffi::c_char,
) -> *mut xberg::ResolvedPreset {
    clear_last_error();
    if preset.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'preset'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees preset is a valid non-null pointer.
    let preset_rs = unsafe { &*preset };
    let custom_schema_rs = if custom_schema.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees custom_schema is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(custom_schema) }.to_str() {
            Ok(s) => match serde_json::from_str(s) {
                Ok(v) => Some(v),
                Err(e) => {
                    set_last_error(2, &format!("Invalid JSON in parameter 'custom_schema': {}", e));
                    return std::ptr::null_mut();
                }
            },
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'custom_schema'");
                return std::ptr::null_mut();
            }
        }
    };
    if context.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'context'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees context is a valid pointer; string is valid UTF-8 from caller.
    let context_rs_str = match unsafe { CStr::from_ptr(context) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'context'");
            return std::ptr::null_mut();
        }
    };
    let context_rs = match serde_json::from_str::<std::collections::HashMap<String, String>>(context_rs_str) {
        Ok(v) => v,
        Err(e) => {
            set_last_error(2, &e.to_string());
            return std::ptr::null_mut();
        }
    };
    let context_btree = context_rs.into_iter().collect::<std::collections::BTreeMap<_, _>>();
    let result = xberg::resolve(&preset_rs, custom_schema_rs, &context_btree);
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

