/// Render a single PDF page to PNG bytes.
///
/// Returns raw PNG-encoded bytes for the specified page at the given DPI.
/// Uses pdf_oxide with tiny-skia for pure-Rust rendering.
///
/// For pages with extreme dimensions (very wide vector diagrams, etc.) the
/// effective DPI may be automatically reduced to avoid rasterizer failure.
/// A warning is logged when this happens.
/// \param pdf_bytes Raw PDF file bytes
/// \param page_index Zero-based page index
/// \param dpi Resolution in dots per inch (default: 150)
/// \param password Optional password for encrypted PDFs
/// \note Returns `XbergError::Parsing` if the PDF cannot be opened, authenticated,
/// or rendered, or if `page_index` is out of range.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[allow(clippy::too_many_arguments)]
#[cfg(feature = "pdf")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_render_pdf_page_to_png(
    pdf_bytes: *const u8,
    pdf_bytes_len: usize,
    page_index: usize,
    dpi: i32,
    password: *const std::ffi::c_char,
    out_ptr: *mut *mut u8,
    out_len: *mut usize,
    out_cap: *mut usize,
) -> i32 {
    clear_last_error();
    if out_ptr.is_null() || out_len.is_null() || out_cap.is_null() {
        set_last_error(1, "Null out-param pointer for byte buffer return");
        return -1;
    }
    if pdf_bytes.is_null() && pdf_bytes_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'pdf_bytes'");
        return -1;
    }
    // SAFETY: when pdf_bytes is null, pdf_bytes_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let pdf_bytes_rs = if pdf_bytes.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(pdf_bytes, pdf_bytes_len) }.to_vec()
    };
    let page_index_rs = page_index;
    // Optional numeric primitive: max value of type = None
    let dpi_rs = if dpi == i32::MAX { None } else { Some(dpi) };
    let password_rs = if password.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees password is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(password) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'password'");
                return -1;
            }
        }
    };
    let result = xberg::render_pdf_page_to_png(&pdf_bytes_rs, page_index_rs, dpi_rs, password_rs.as_deref());
    match result {
        Ok(val) => {
            // Convert via Vec<u8> so the path works for both Vec<u8> and bytes::Bytes
            // (and any other type that implements Into<Vec<u8>>).
            let (ptr, len, cap) = Vec::<u8>::from(val).into_raw_parts();
            // SAFETY: out_ptr/out_len/out_cap were null-checked above.
            unsafe {
                *out_ptr = ptr;
                *out_len = len;
                *out_cap = cap;
            }
            0
        }
        Err(e) => {
            set_last_error(2, &e.to_string());
            // SAFETY: out_ptr/out_len/out_cap were null-checked above.
            unsafe {
                *out_ptr = std::ptr::null_mut();
                *out_len = 0;
                *out_cap = 0;
            }
            -1
        }
    }
}

/// Count the pages in a PDF without rendering any of them.
///
/// Opens the document and returns its page count from the PDF structure. No page
/// is rasterized, so this is cheap relative to `render_pdf_page_to_png` â use it
/// when you only need the count (e.g. to drive a render loop over the pages).
/// \param pdf_bytes Raw PDF file bytes
/// \param password Optional password for encrypted PDFs
/// \note Returns `XbergError::Parsing` if the PDF cannot be opened, authenticated,
/// or its page count read.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[cfg(feature = "pdf")]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_pdf_page_count(
    pdf_bytes: *const u8,
    pdf_bytes_len: usize,
    password: *const std::ffi::c_char,
) -> usize {
    clear_last_error();
    if pdf_bytes.is_null() && pdf_bytes_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'pdf_bytes'");
        return 0;
    }
    // SAFETY: when pdf_bytes is null, pdf_bytes_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let pdf_bytes_rs = if pdf_bytes.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(pdf_bytes, pdf_bytes_len) }.to_vec()
    };
    let password_rs = if password.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees password is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(password) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'password'");
                return 0;
            }
        }
    };
    let result = xberg::pdf_page_count(&pdf_bytes_rs, password_rs.as_deref());
    match result {
        Ok(val) => val,
        Err(e) => {
            set_last_error(2, &e.to_string());
            0
        }
    }
}

