/// Write an error message string into an FFI out-error pointer.
///
/// # Safety
///
/// `out_error` must be null or a valid writable `*mut *mut c_char` pointer.
unsafe fn ffi_set_out_error(out_error: *mut *mut std::ffi::c_char, msg: &str) {
    if !out_error.is_null() {
        if let Ok(cs) = std::ffi::CString::new(msg) {
            // SAFETY: out_error is non-null; caller must free this string.
            unsafe {
                *out_error = cs.into_raw();
            }
        }
    }
}

/// VTable for C plugin bridges implementing the `OcrBackend` trait.
///
/// # Safety
///
/// All function pointers must be valid for the lifetime of any bridge created from
/// this vtable.  `free_user_data`, when non-null, is called once with `user_data`
/// when the bridge is dropped.
#[derive(Copy, Clone)]
#[repr(C)]
pub struct XbergOcrBackendVTable {
    /// Return a null-terminated UTF-8 name string into `out_name`; return 0 on success.
    pub name_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_name: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Return a null-terminated UTF-8 version string into `out_version`; return 0 on success.
    pub version_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_version: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Initialise the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub initialize_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Shut down the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub shutdown_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Process an image and extract text via OCR.
    ///
    /// # Arguments
    ///
    /// * `image_bytes` - Raw image data (JPEG, PNG, TIFF, etc.)
    /// * `config` - OCR configuration (language, PSM mode, etc.)
    ///
    /// # Returns
    ///
    /// An `ExtractionResult` containing the extracted text and metadata.
    ///
    /// # Errors
    ///
    /// - `XbergError::Ocr` - OCR processing failed
    /// - `XbergError::Validation` - Invalid image format or configuration
    /// - `XbergError::Io` - I/O errors (these always bubble up)
    ///
    /// # Reading `backend_options`
    ///
    /// Backends that support runtime tuning can read `config.backend_options` and
    /// deserialize only the keys they care about. Unknown keys are silently ignored,
    /// so multiple backends can coexist in a pipeline without key conflicts.
    ///
    /// ```rust
    /// async fn process_image(&self, image_bytes: &[u8], config: &OcrConfig) -> Result<ExtractionResult> {
    /// // Read backend-specific options; unknown keys are silently ignored.
    /// let fast_mode = config.backend_options
    /// .as_ref()
    /// .and_then(|v| v.get("mode"))
    /// .and_then(|v| v.as_str())
    /// .map(|s| s == "fast")
    /// .unwrap_or(false);
    ///
    /// if image_bytes.is_empty() {
    /// return Err(xberg::XbergError::Validation {
    /// message: "Empty image data".to_string(),
    /// source: None,
    /// });
    /// }
    ///
    /// let text = if fast_mode {
    /// "Fast OCR result".to_string()
    /// } else {
    /// format!("Extracted text in language: {}", config.language)
    /// };
    ///
    /// Ok(ExtractionResult {
    /// content: text,
    /// mime_type: Cow::Borrowed("text/plain"),
    /// ..Default::default()
    /// })
    /// }
    /// ```
    pub process_image: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            image_bytes: *const u8,
            image_bytes_len: usize,
            config: *const std::ffi::c_char,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Process a file and extract text via OCR.
    ///
    /// Default implementation reads the file and calls `process_image`.
    /// Override for custom file handling or optimizations.
    ///
    /// # Arguments
    ///
    /// * `path` - Path to the image file
    /// * `config` - OCR configuration
    ///
    /// # Errors
    ///
    /// Same as `process_image`, plus file I/O errors.
    pub process_image_file: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            path: *const std::ffi::c_char,
            config: *const std::ffi::c_char,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Check if this backend supports a given language code.
    ///
    /// # Arguments
    ///
    /// * `lang` - ISO 639-2/3 language code (e.g., "eng", "deu", "fra")
    ///
    /// # Returns
    ///
    /// `true` if the language is supported, `false` otherwise.
    ///
    /// # Example
    ///
    /// ```rust
    /// fn supports_language(&self, lang: &str) -> bool {
    /// self.languages.contains(&lang.to_string())
    /// }
    /// ```
    pub supports_language:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, lang: *const std::ffi::c_char) -> i32>,
    /// Get the backend type identifier.
    ///
    /// # Returns
    ///
    /// The backend type enum value.
    ///
    /// # Example
    ///
    /// ```rust
    /// fn backend_type(&self) -> OcrBackendType {
    /// OcrBackendType::Tesseract
    /// }
    /// ```
    pub backend_type: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional: Get a list of all supported languages.
    ///
    /// Defaults to empty list. Override to provide comprehensive language support info.
    pub supported_languages: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional: Check if the backend supports table detection.
    ///
    /// Defaults to `false`. Override if your backend can detect and extract tables.
    pub supports_table_detection: Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void) -> i32>,
    /// Check if the backend supports direct document-level processing (e.g. for PDFs).
    ///
    /// Defaults to `false`. Override if the backend has optimized document processing.
    pub supports_document_processing: Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void) -> i32>,
    /// Declare that this backend emits structured markdown directly (tables, headings, lists)
    /// and downstream layout reconstruction should be skipped.
    ///
    /// Defaults to `false` — classical OCR backends (Tesseract, PaddleOCR classical) return
    /// plain text per detected region. End-to-end VLM backends (PaddleOCR-VL, GOT-OCR 2.0)
    /// emit markdown in one forward pass and should override this to `true`.
    pub emits_structured_markdown: Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void) -> i32>,
    /// Process a document file directly via OCR.
    ///
    /// Only called if `supports_document_processing` returns `true`.
    ///
    /// # Arguments
    ///
    /// * `path` - Path to the document file (e.g. .pdf)
    /// * `config` - OCR configuration
    pub process_document: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            _path: *const std::ffi::c_char,
            _config: *const std::ffi::c_char,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional string destructor: called for strings returned by vtable callbacks.
    pub free_string: Option<unsafe extern "C" fn(*mut std::ffi::c_char)>,
    /// Optional destructor: called once with `user_data` when the bridge is dropped.
    pub free_user_data: Option<unsafe extern "C" fn(*mut std::ffi::c_void)>,
}

// SAFETY: all fields are function pointers and free_user_data, which are Send + Sync.
unsafe impl Send for XbergOcrBackendVTable {}
unsafe impl Sync for XbergOcrBackendVTable {}

/// Rust-side bridge that holds a C vtable pointer and opaque `user_data`.
///
/// Implements `OcrBackend` by forwarding calls through the vtable.
pub struct XbergOcrBackendBridge {
    vtable: XbergOcrBackendVTable,
    user_data: *const std::ffi::c_void,
    cached_name: String,
    cached_version: String,
}

impl std::fmt::Debug for XbergOcrBackendBridge {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("XbergOcrBackendBridge")
            .field("cached_name", &self.cached_name)
            .field("cached_version", &self.cached_version)
            .finish_non_exhaustive()
    }
}

// SAFETY: The caller is responsible for ensuring `user_data` is safe to send across
// thread boundaries. This is documented in `XbergOcrBackendVTable` and the registration function.
unsafe impl Send for XbergOcrBackendBridge {}
unsafe impl Sync for XbergOcrBackendBridge {}

impl Drop for XbergOcrBackendBridge {
    fn drop(&mut self) {
        if let Some(free_fn) = self.vtable.free_user_data {
            // SAFETY: free_fn is a valid function pointer; user_data is the pointer
            // originally provided at registration. Called exactly once here.
            unsafe { free_fn(self.user_data as *mut std::ffi::c_void) }
        }
    }
}

impl XbergOcrBackendBridge {
    /// Create a new bridge from a vtable and opaque user_data pointer.
    ///
    /// # Safety
    ///
    /// `vtable` must remain valid for the lifetime of the returned bridge.
    /// `user_data` must be valid for any thread that calls methods on this bridge.
    /// All required fn pointers in `vtable` must be non-null.
    pub unsafe fn new(name: String, vtable: XbergOcrBackendVTable, user_data: *const std::ffi::c_void) -> Self {
        Self {
            vtable,
            user_data,
            cached_name: name,
            cached_version: String::new(),
        }
    }
}

impl xberg::plugins::Plugin for XbergOcrBackendBridge {
    fn name(&self) -> &str {
        &self.cached_name
    }
    fn version(&self) -> String {
        let Some(fp) = self.vtable.version_fn else {
            return String::new();
        };
        let mut _out: *mut std::ffi::c_char = std::ptr::null_mut();
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out, &mut _out_error) };
        if rc != 0 {
            if !_out_error.is_null() {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let _ = unsafe { std::ffi::CStr::from_ptr(_out_error) }.to_string_lossy();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
            }
            return self.cached_version.clone();
        }
        if _out.is_null() {
            return self.cached_version.clone();
        }
        // SAFETY: _out is a callee-allocated NUL-terminated string.
        let version = unsafe { std::ffi::CStr::from_ptr(_out) }.to_string_lossy().into_owned();
        if let Some(free_fn) = self.vtable.free_string {
            // SAFETY: free_fn is the vtable-provided destructor for callback strings.
            unsafe { free_fn(_out) };
        }
        version
    }
    fn initialize(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.initialize_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("initialize returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
    fn shutdown(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.shutdown_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("shutdown returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
}

