/// Register a C plugin implementing `OcrBackend` via a vtable.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `vtable`: vtable with function pointers implementing the trait.
/// - `user_data`: opaque pointer forwarded to every vtable function.
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// All function pointers in `vtable` must remain valid until the plugin is
/// unregistered. `user_data` must be safe to use from any thread that calls
/// into the plugin.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_register_ocr_backend(
    name: *const std::ffi::c_char,
    vtable: *const XbergOcrBackendVTable,
    user_data: *const std::ffi::c_void,
    out_error: *mut *mut std::ffi::c_char,
) -> i32 {
    if name.is_null() {
        ffi_set_out_error(out_error, "name must not be null");
        return 1;
    }
    if vtable.is_null() {
        ffi_set_out_error(out_error, "vtable must not be null");
        return 1;
    }
    let vtable_ref = &*vtable;
    if vtable_ref.free_string.is_none() {
        ffi_set_out_error(out_error, "vtable.free_string must not be null");
        return 1;
    }
    if vtable_ref.process_image.is_none() {
        ffi_set_out_error(out_error, "vtable.process_image must not be null");
        return 1;
    }
    if vtable_ref.supports_language.is_none() {
        ffi_set_out_error(out_error, "vtable.supports_language must not be null");
        return 1;
    }
    if vtable_ref.backend_type.is_none() {
        ffi_set_out_error(out_error, "vtable.backend_type must not be null");
        return 1;
    }

    // SAFETY: name is non-null (checked above); it points to a valid C string.
    let plugin_name = match unsafe { std::ffi::CStr::from_ptr(name) }.to_str() {
        Ok(s) => s.to_owned(),
        Err(_) => {
            ffi_set_out_error(out_error, "name is not valid UTF-8");
            return 1;
        }
    };

    // SAFETY: vtable pointer and user_data validity is the caller's responsibility.
    let bridge = unsafe { XbergOcrBackendBridge::new(plugin_name, *vtable_ref, user_data) };
    let arc: Arc<dyn xberg::OcrBackend> = Arc::new(bridge);

    let registry = xberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write();

    if let Err(e) = registry.register(arc) {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// Unregister a previously registered C plugin by name.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// `name` must point to a valid null-terminated C string.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_unregister_ocr_backend(
    name: *const std::ffi::c_char,
    out_error: *mut *mut std::ffi::c_char,
) -> i32 {
    if name.is_null() {
        ffi_set_out_error(out_error, "name must not be null");
        return 1;
    }
    // SAFETY: name is non-null (checked above); it points to a valid C string.
    let plugin_name = match unsafe { std::ffi::CStr::from_ptr(name) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            ffi_set_out_error(out_error, "name is not valid UTF-8");
            return 1;
        }
    };

    let registry = xberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write();
    if let Err(e) = registry.remove(plugin_name) {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// Remove all registered C plugins of this trait.
///
/// # Parameters
///
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// `out_error` may be null. When non-null, the caller owns the resulting string
/// and must free it with `xberg_free_string`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_clear_ocr_backend(out_error: *mut *mut std::ffi::c_char) -> i32 {
    let registry = xberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write();
    if let Err(e) = registry.clear() {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// VTable for C plugin bridges implementing the `PostProcessor` trait.
///
/// # Safety
///
/// All function pointers must be valid for the lifetime of any bridge created from
/// this vtable.  `free_user_data`, when non-null, is called once with `user_data`
/// when the bridge is dropped.
#[derive(Copy, Clone)]
#[repr(C)]
pub struct XbergPostProcessorVTable {
    /// Return a null-terminated UTF-8 name string into `out_name`; return 0 on success.
    pub name_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_name: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Return a null-terminated UTF-8 version string into `out_version`; return 0 on success.
    pub version_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_version: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Initialise the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub initialize_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Shut down the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub shutdown_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Process an extraction result.
    ///
    /// Transform or enrich the extraction result. Can modify:
    /// - `content` - The extracted text
    /// - `metadata` - Add or update metadata fields
    /// - `tables` - Modify or enhance table data
    ///
    /// # Arguments
    ///
    /// * `result` - Mutable reference to the extraction result to process
    /// * `config` - Extraction configuration
    ///
    /// # Returns
    ///
    /// `Ok(())` if processing succeeded, `Err(...)` for fatal failures.
    ///
    /// # Errors
    ///
    /// Return errors for fatal processing failures. Non-fatal errors should be
    /// captured in metadata directly on the result.
    ///
    /// # Performance
    ///
    /// This signature avoids unnecessary cloning of large extraction results by
    /// taking a mutable reference instead of ownership. Processors modify the
    /// result in place.
    ///
    /// # Example - Language Detection
    ///
    /// ```rust
    /// async fn process(&self, result: &mut ExtractionResult, config: &ExtractionConfig)
    /// -> Result<()> {
    /// // Detect language (simplified - use real detection library in practice)
    /// let language = "en"; // Placeholder detection
    ///
    /// // Add to metadata
    /// result.metadata.additional.insert("detected_language".to_string().into(), serde_json::json!(language));
    ///
    /// Ok(())
    /// }
    /// ```
    ///
    /// # Example - Text Cleaning
    ///
    /// ```rust
    /// async fn process(&self, result: &mut ExtractionResult, config: &ExtractionConfig)
    /// -> Result<()> {
    /// // Remove excessive whitespace
    /// result.content = result
    /// .content
    /// .split_whitespace()
    /// .collect::<Vec<_>>()
    /// .join(" ");
    ///
    /// Ok(())
    /// }
    /// ```
    pub process: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            result: *const std::ffi::c_char,
            config: *const std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Get the processing stage for this post-processor.
    ///
    /// Determines when this processor runs in the pipeline.
    ///
    /// # Returns
    ///
    /// The `ProcessingStage` (Early, Middle, or Late).
    ///
    /// # Example
    ///
    /// ```rust
    /// fn processing_stage(&self) -> ProcessingStage {
    /// ProcessingStage::Early  // Run before other processors
    /// }
    /// ```
    pub processing_stage: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional: Check if this processor should run for a given result.
    ///
    /// Allows conditional processing based on MIME type, metadata, or content.
    /// Defaults to `true` (always run).
    ///
    /// # Arguments
    ///
    /// * `result` - The extraction result to check
    /// * `config` - Extraction configuration
    ///
    /// # Returns
    ///
    /// `true` if the processor should run, `false` to skip.
    ///
    /// # Example
    ///
    /// ```rust
    /// Only process PDF documents
    /// fn should_process(&self, result: &ExtractionResult, config: &ExtractionConfig) -> bool {
    /// result.mime_type == "application/pdf"
    /// }
    /// ```
    pub should_process: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            _result: *const std::ffi::c_char,
            _config: *const std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional: Estimate processing time in milliseconds.
    ///
    /// Used for logging and debugging. Defaults to 0 (unknown).
    ///
    /// # Arguments
    ///
    /// * `result` - The extraction result to estimate for
    ///
    /// # Returns
    ///
    /// Estimated processing time in milliseconds.
    pub estimated_duration_ms:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, _result: *const std::ffi::c_char) -> u64>,
    /// Execution priority within the processing stage.
    ///
    /// Higher values run first within the same `ProcessingStage`. Defaults to 50.
    /// Use 0-49 for fallback processors, 50 for normal processors, and 51-255
    /// for high-priority processors that should run early in their stage.
    pub priority: Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void) -> i32>,
    /// Optional string destructor: called for strings returned by vtable callbacks.
    pub free_string: Option<unsafe extern "C" fn(*mut std::ffi::c_char)>,
    /// Optional destructor: called once with `user_data` when the bridge is dropped.
    pub free_user_data: Option<unsafe extern "C" fn(*mut std::ffi::c_void)>,
}

// SAFETY: all fields are function pointers and free_user_data, which are Send + Sync.
unsafe impl Send for XbergPostProcessorVTable {}
unsafe impl Sync for XbergPostProcessorVTable {}

/// Rust-side bridge that holds a C vtable pointer and opaque `user_data`.
///
/// Implements `PostProcessor` by forwarding calls through the vtable.
pub struct XbergPostProcessorBridge {
    vtable: XbergPostProcessorVTable,
    user_data: *const std::ffi::c_void,
    cached_name: String,
    cached_version: String,
}

impl std::fmt::Debug for XbergPostProcessorBridge {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("XbergPostProcessorBridge")
            .field("cached_name", &self.cached_name)
            .field("cached_version", &self.cached_version)
            .finish_non_exhaustive()
    }
}

// SAFETY: The caller is responsible for ensuring `user_data` is safe to send across
// thread boundaries. This is documented in `XbergPostProcessorVTable` and the registration function.
unsafe impl Send for XbergPostProcessorBridge {}
unsafe impl Sync for XbergPostProcessorBridge {}

impl Drop for XbergPostProcessorBridge {
    fn drop(&mut self) {
        if let Some(free_fn) = self.vtable.free_user_data {
            // SAFETY: free_fn is a valid function pointer; user_data is the pointer
            // originally provided at registration. Called exactly once here.
            unsafe { free_fn(self.user_data as *mut std::ffi::c_void) }
        }
    }
}

impl XbergPostProcessorBridge {
    /// Create a new bridge from a vtable and opaque user_data pointer.
    ///
    /// # Safety
    ///
    /// `vtable` must remain valid for the lifetime of the returned bridge.
    /// `user_data` must be valid for any thread that calls methods on this bridge.
    /// All required fn pointers in `vtable` must be non-null.
    pub unsafe fn new(name: String, vtable: XbergPostProcessorVTable, user_data: *const std::ffi::c_void) -> Self {
        Self {
            vtable,
            user_data,
            cached_name: name,
            cached_version: String::new(),
        }
    }
}

impl xberg::plugins::Plugin for XbergPostProcessorBridge {
    fn name(&self) -> &str {
        &self.cached_name
    }
    fn version(&self) -> String {
        let Some(fp) = self.vtable.version_fn else {
            return String::new();
        };
        let mut _out: *mut std::ffi::c_char = std::ptr::null_mut();
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out, &mut _out_error) };
        if rc != 0 {
            if !_out_error.is_null() {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let _ = unsafe { std::ffi::CStr::from_ptr(_out_error) }.to_string_lossy();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
            }
            return self.cached_version.clone();
        }
        if _out.is_null() {
            return self.cached_version.clone();
        }
        // SAFETY: _out is a callee-allocated NUL-terminated string.
        let version = unsafe { std::ffi::CStr::from_ptr(_out) }.to_string_lossy().into_owned();
        if let Some(free_fn) = self.vtable.free_string {
            // SAFETY: free_fn is the vtable-provided destructor for callback strings.
            unsafe { free_fn(_out) };
        }
        version
    }
    fn initialize(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.initialize_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("initialize returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
    fn shutdown(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.shutdown_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("shutdown returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
}

#[async_trait::async_trait]
impl xberg::PostProcessor for XbergPostProcessorBridge {
    async fn process(
        &self,
        result: &mut xberg::ExtractionResult,
        config: &xberg::ExtractionConfig,
    ) -> std::result::Result<(), xberg::XbergError> {
        struct _SendFn<F>(F);
        // SAFETY: caller guarantees vtable fn pointers and user_data are valid across threads.
        unsafe impl<F> Send for _SendFn<F> {}
        impl<F: FnOnce() -> R, R> _SendFn<F> {
            fn call(self) -> R {
                (self.0)()
            }
        }

        let _cached_name = self.cached_name.clone();
        let vtable = self.vtable;
        let user_data = self.user_data;
        let result = result.clone();
        let config = config.clone();

        let _task = _SendFn(move || {
            // Inline the sync body:
            let Some(fp) = vtable.process else {
                return Err(Box::from("vtable.process is null — bridge not initialised"));
            };
            let _result_json = serde_json::to_string(&result).unwrap_or_default();
            let _result_cs = match std::ffi::CString::new(_result_json) {
                Ok(s) => s,
                Err(_) => {
                    return Err(Box::from("nul byte in serialized param result"));
                }
            };
            let result_ptr = _result_cs.as_ptr();
            let _config_json = serde_json::to_string(&config).unwrap_or_default();
            let _config_cs = match std::ffi::CString::new(_config_json) {
                Ok(s) => s,
                Err(_) => {
                    return Err(Box::from("nul byte in serialized param config"));
                }
            };
            let config_ptr = _config_cs.as_ptr();
            let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
            // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
            // user_data validity is the caller's responsibility (documented in the vtable API).
            let _rc = unsafe { fp(user_data, result_ptr, config_ptr, &mut _out_error) };
            if _rc != 0 {
                let msg = if _out_error.is_null() {
                    format!("vtable.process returned error code {}", _rc)
                } else {
                    // SAFETY: out_error was written by the callee as a valid NUL-terminated string.
                    let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                        .to_string_lossy()
                        .into_owned();
                    if let Some(free_fn) = vtable.free_string {
                        // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                        unsafe { free_fn(_out_error) };
                    }
                    msg
                };
                return Err(Box::from(msg));
            }
            Ok(())
        });
        tokio::task::spawn_blocking(move || _task.call())
            .await
            .map_err(|e| xberg::XbergError::Other(format!("spawn_blocking failed in process: {}", e)))?
            .map_err(|e: Box<dyn std::error::Error + Send + Sync>| xberg::XbergError::Other(e.to_string()))
    }

    fn processing_stage(&self) -> xberg::ProcessingStage {
        let Some(fp) = self.vtable.processing_stage else {
            return Default::default();
        };
        let mut _out_result: *mut std::ffi::c_char = std::ptr::null_mut();
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
        // user_data validity is the caller's responsibility (documented in the vtable API).
        let _rc = unsafe { fp(self.user_data, &mut _out_result, &mut _out_error) };
        if _out_result.is_null() {
            return Default::default();
        }
        // SAFETY: out_result was written by the callee as a valid NUL-terminated string.
        let json = unsafe { std::ffi::CStr::from_ptr(_out_result) }
            .to_string_lossy()
            .into_owned();
        if let Some(free_fn) = self.vtable.free_string {
            // SAFETY: free_fn is the vtable-provided destructor for callback strings.
            unsafe { free_fn(_out_result) };
        }
        serde_json::from_str::<xberg::ProcessingStage>(&json).unwrap_or_default()
    }

    fn should_process(&self, _result: &xberg::ExtractionResult, _config: &xberg::ExtractionConfig) -> bool {
        let Some(fp) = self.vtable.should_process else {
            return false;
        };
        let __result_json = serde_json::to_string(&_result).unwrap_or_default();
        let __result_cs = match std::ffi::CString::new(__result_json) {
            Ok(s) => s,
            Err(_) => {
                return false;
            }
        };
        let _result_ptr = __result_cs.as_ptr();
        let __config_json = serde_json::to_string(&_config).unwrap_or_default();
        let __config_cs = match std::ffi::CString::new(__config_json) {
            Ok(s) => s,
            Err(_) => {
                return false;
            }
        };
        let _config_ptr = __config_cs.as_ptr();
        // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
        // user_data validity is the caller's responsibility (documented in the vtable API).
        let _rc = unsafe { fp(self.user_data, _result_ptr, _config_ptr) };
        _rc != 0
    }

    fn estimated_duration_ms(&self, _result: &xberg::ExtractionResult) -> u64 {
        let Some(fp) = self.vtable.estimated_duration_ms else {
            return 0;
        };
        let __result_json = serde_json::to_string(&_result).unwrap_or_default();
        let __result_cs = match std::ffi::CString::new(__result_json) {
            Ok(s) => s,
            Err(_) => {
                return 0;
            }
        };
        let _result_ptr = __result_cs.as_ptr();
        // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
        // user_data validity is the caller's responsibility (documented in the vtable API).
        unsafe { fp(self.user_data, _result_ptr) }
    }

    fn priority(&self) -> i32 {
        let Some(fp) = self.vtable.priority else {
            return 0;
        };
        // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
        // user_data validity is the caller's responsibility (documented in the vtable API).
        unsafe { fp(self.user_data) }
    }
}

/// Register a C plugin implementing `PostProcessor` via a vtable.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `vtable`: vtable with function pointers implementing the trait.
/// - `user_data`: opaque pointer forwarded to every vtable function.
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// All function pointers in `vtable` must remain valid until the plugin is
/// unregistered. `user_data` must be safe to use from any thread that calls
/// into the plugin.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_register_post_processor(
    name: *const std::ffi::c_char,
    vtable: *const XbergPostProcessorVTable,
    user_data: *const std::ffi::c_void,
    out_error: *mut *mut std::ffi::c_char,
) -> i32 {
    if name.is_null() {
        ffi_set_out_error(out_error, "name must not be null");
        return 1;
    }
    if vtable.is_null() {
        ffi_set_out_error(out_error, "vtable must not be null");
        return 1;
    }
    let vtable_ref = &*vtable;
    if vtable_ref.free_string.is_none() {
        ffi_set_out_error(out_error, "vtable.free_string must not be null");
        return 1;
    }
    if vtable_ref.process.is_none() {
        ffi_set_out_error(out_error, "vtable.process must not be null");
        return 1;
    }
    if vtable_ref.processing_stage.is_none() {
        ffi_set_out_error(out_error, "vtable.processing_stage must not be null");
        return 1;
    }

    // SAFETY: name is non-null (checked above); it points to a valid C string.
    let plugin_name = match unsafe { std::ffi::CStr::from_ptr(name) }.to_str() {
        Ok(s) => s.to_owned(),
        Err(_) => {
            ffi_set_out_error(out_error, "name is not valid UTF-8");
            return 1;
        }
    };

    // SAFETY: vtable pointer and user_data validity is the caller's responsibility.
    let bridge = unsafe { XbergPostProcessorBridge::new(plugin_name, *vtable_ref, user_data) };
    let arc: Arc<dyn xberg::PostProcessor> = Arc::new(bridge);

    let registry = xberg::plugins::registry::get_post_processor_registry();
    let mut registry = registry.write();

    if let Err(e) = registry.register(arc) {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// Unregister a previously registered C plugin by name.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// `name` must point to a valid null-terminated C string.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_unregister_post_processor(
    name: *const std::ffi::c_char,
    out_error: *mut *mut std::ffi::c_char,
) -> i32 {
    if name.is_null() {
        ffi_set_out_error(out_error, "name must not be null");
        return 1;
    }
    // SAFETY: name is non-null (checked above); it points to a valid C string.
    let plugin_name = match unsafe { std::ffi::CStr::from_ptr(name) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            ffi_set_out_error(out_error, "name is not valid UTF-8");
            return 1;
        }
    };

    let registry = xberg::plugins::registry::get_post_processor_registry();
    let mut registry = registry.write();
    if let Err(e) = registry.remove(plugin_name) {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// Remove all registered C plugins of this trait.
///
/// # Parameters
///
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// `out_error` may be null. When non-null, the caller owns the resulting string
/// and must free it with `xberg_free_string`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_clear_post_processor(out_error: *mut *mut std::ffi::c_char) -> i32 {
    let registry = xberg::plugins::registry::get_post_processor_registry();
    let mut registry = registry.write();
    if let Err(e) = registry.clear() {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// VTable for C plugin bridges implementing the `Validator` trait.
///
/// # Safety
///
/// All function pointers must be valid for the lifetime of any bridge created from
/// this vtable.  `free_user_data`, when non-null, is called once with `user_data`
/// when the bridge is dropped.
#[derive(Copy, Clone)]
#[repr(C)]
pub struct XbergValidatorVTable {
    /// Return a null-terminated UTF-8 name string into `out_name`; return 0 on success.
    pub name_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_name: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Return a null-terminated UTF-8 version string into `out_version`; return 0 on success.
    pub version_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_version: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Initialise the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub initialize_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Shut down the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub shutdown_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Validate an extraction result.
    ///
    /// Check the extraction result and return `Ok(())` if valid, or an error
    /// if validation fails.
    ///
    /// # Arguments
    ///
    /// * `result` - The extraction result to validate
    /// * `config` - Extraction configuration
    ///
    /// # Returns
    ///
    /// - `Ok(())` if validation passes
    /// - `Err(...)` if validation fails (extraction will fail)
    ///
    /// # Errors
    ///
    /// - `XbergError::Validation` - Validation failed
    /// - Any other error type appropriate for the failure
    ///
    /// # Example - Content Length Validation
    ///
    /// ```rust
    /// async fn validate(&self, result: &ExtractionResult, config: &ExtractionConfig)
    /// -> Result<()> {
    /// let length = result.content.len();
    ///
    /// if length < self.min {
    /// return Err(XbergError::validation(format!(
    /// "Content too short: {} < {} characters",
    /// length, self.min
    /// )));
    /// }
    ///
    /// if length > self.max {
    /// return Err(XbergError::validation(format!(
    /// "Content too long: {} > {} characters",
    /// length, self.max
    /// )));
    /// }
    ///
    /// Ok(())
    /// }
    /// ```
    ///
    /// # Example - Quality Score Validation
    ///
    /// ```rust
    /// async fn validate(&self, result: &ExtractionResult, config: &ExtractionConfig)
    /// -> Result<()> {
    /// // Check if quality_score exists in metadata
    /// let score = result.metadata
    /// .additional
    /// .get("quality_score")
    /// .and_then(|v| v.as_f64())
    /// .unwrap_or(0.0);
    ///
    /// if score < self.min_score {
    /// return Err(XbergError::validation(format!(
    /// "Quality score too low: {} < {}",
    /// score, self.min_score
    /// )));
    /// }
    ///
    /// Ok(())
    /// }
    /// ```
    ///
    /// # Example - Security Validation
    ///
    /// ```rust
    /// async fn validate(&self, result: &ExtractionResult, config: &ExtractionConfig)
    /// -> Result<()> {
    /// // Check for blocked patterns
    /// for pattern in &self.blocked_patterns {
    /// if result.content.contains(pattern) {
    /// return Err(XbergError::validation(format!(
    /// "Content contains blocked pattern: {}",
    /// pattern
    /// )));
    /// }
    /// }
    ///
    /// Ok(())
    /// }
    /// ```
    pub validate: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            result: *const std::ffi::c_char,
            config: *const std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional: Check if this validator should run for a given result.
    ///
    /// Allows conditional validation based on MIME type, metadata, or content.
    /// Defaults to `true` (always run).
    ///
    /// # Arguments
    ///
    /// * `result` - The extraction result to check
    /// * `config` - Extraction configuration
    ///
    /// # Returns
    ///
    /// `true` if the validator should run, `false` to skip.
    ///
    /// # Example
    ///
    /// ```rust
    /// Only validate PDF documents
    /// fn should_validate(&self, result: &ExtractionResult, config: &ExtractionConfig) -> bool {
    /// result.mime_type == "application/pdf"
    /// }
    /// ```
    pub should_validate: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            _result: *const std::ffi::c_char,
            _config: *const std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional: Get the validation priority.
    ///
    /// Higher priority validators run first. Useful for ordering validation checks
    /// (e.g., run cheap validations before expensive ones).
    ///
    /// Default priority is 50.
    ///
    /// # Returns
    ///
    /// Priority value (higher = runs earlier).
    ///
    /// # Example
    ///
    /// ```rust
    /// Run this validator first (it's fast)
    /// fn priority(&self) -> i32 {
    /// 100
    /// }
    /// ```
    pub priority: Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void) -> i32>,
    /// Optional string destructor: called for strings returned by vtable callbacks.
    pub free_string: Option<unsafe extern "C" fn(*mut std::ffi::c_char)>,
    /// Optional destructor: called once with `user_data` when the bridge is dropped.
    pub free_user_data: Option<unsafe extern "C" fn(*mut std::ffi::c_void)>,
}

// SAFETY: all fields are function pointers and free_user_data, which are Send + Sync.
unsafe impl Send for XbergValidatorVTable {}
unsafe impl Sync for XbergValidatorVTable {}

/// Rust-side bridge that holds a C vtable pointer and opaque `user_data`.
///
/// Implements `Validator` by forwarding calls through the vtable.
pub struct XbergValidatorBridge {
    vtable: XbergValidatorVTable,
    user_data: *const std::ffi::c_void,
    cached_name: String,
    cached_version: String,
}

impl std::fmt::Debug for XbergValidatorBridge {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("XbergValidatorBridge")
            .field("cached_name", &self.cached_name)
            .field("cached_version", &self.cached_version)
            .finish_non_exhaustive()
    }
}

// SAFETY: The caller is responsible for ensuring `user_data` is safe to send across
// thread boundaries. This is documented in `XbergValidatorVTable` and the registration function.
unsafe impl Send for XbergValidatorBridge {}
unsafe impl Sync for XbergValidatorBridge {}

impl Drop for XbergValidatorBridge {
    fn drop(&mut self) {
        if let Some(free_fn) = self.vtable.free_user_data {
            // SAFETY: free_fn is a valid function pointer; user_data is the pointer
            // originally provided at registration. Called exactly once here.
            unsafe { free_fn(self.user_data as *mut std::ffi::c_void) }
        }
    }
}

impl XbergValidatorBridge {
    /// Create a new bridge from a vtable and opaque user_data pointer.
    ///
    /// # Safety
    ///
    /// `vtable` must remain valid for the lifetime of the returned bridge.
    /// `user_data` must be valid for any thread that calls methods on this bridge.
    /// All required fn pointers in `vtable` must be non-null.
    pub unsafe fn new(name: String, vtable: XbergValidatorVTable, user_data: *const std::ffi::c_void) -> Self {
        Self {
            vtable,
            user_data,
            cached_name: name,
            cached_version: String::new(),
        }
    }
}

impl xberg::plugins::Plugin for XbergValidatorBridge {
    fn name(&self) -> &str {
        &self.cached_name
    }
    fn version(&self) -> String {
        let Some(fp) = self.vtable.version_fn else {
            return String::new();
        };
        let mut _out: *mut std::ffi::c_char = std::ptr::null_mut();
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out, &mut _out_error) };
        if rc != 0 {
            if !_out_error.is_null() {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let _ = unsafe { std::ffi::CStr::from_ptr(_out_error) }.to_string_lossy();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
            }
            return self.cached_version.clone();
        }
        if _out.is_null() {
            return self.cached_version.clone();
        }
        // SAFETY: _out is a callee-allocated NUL-terminated string.
        let version = unsafe { std::ffi::CStr::from_ptr(_out) }.to_string_lossy().into_owned();
        if let Some(free_fn) = self.vtable.free_string {
            // SAFETY: free_fn is the vtable-provided destructor for callback strings.
            unsafe { free_fn(_out) };
        }
        version
    }
    fn initialize(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.initialize_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("initialize returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
    fn shutdown(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.shutdown_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("shutdown returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
}

#[async_trait::async_trait]
impl xberg::Validator for XbergValidatorBridge {
    async fn validate(
        &self,
        result: &xberg::ExtractionResult,
        config: &xberg::ExtractionConfig,
    ) -> std::result::Result<(), xberg::XbergError> {
        struct _SendFn<F>(F);
        // SAFETY: caller guarantees vtable fn pointers and user_data are valid across threads.
        unsafe impl<F> Send for _SendFn<F> {}
        impl<F: FnOnce() -> R, R> _SendFn<F> {
            fn call(self) -> R {
                (self.0)()
            }
        }

        let _cached_name = self.cached_name.clone();
        let vtable = self.vtable;
        let user_data = self.user_data;
        let result = result.clone();
        let config = config.clone();

        let _task = _SendFn(move || {
            // Inline the sync body:
            let Some(fp) = vtable.validate else {
                return Err(Box::from("vtable.validate is null — bridge not initialised"));
            };
            let _result_json = serde_json::to_string(&result).unwrap_or_default();
            let _result_cs = match std::ffi::CString::new(_result_json) {
                Ok(s) => s,
                Err(_) => {
                    return Err(Box::from("nul byte in serialized param result"));
                }
            };
            let result_ptr = _result_cs.as_ptr();
            let _config_json = serde_json::to_string(&config).unwrap_or_default();
            let _config_cs = match std::ffi::CString::new(_config_json) {
                Ok(s) => s,
                Err(_) => {
                    return Err(Box::from("nul byte in serialized param config"));
                }
            };
            let config_ptr = _config_cs.as_ptr();
            let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
            // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
            // user_data validity is the caller's responsibility (documented in the vtable API).
            let _rc = unsafe { fp(user_data, result_ptr, config_ptr, &mut _out_error) };
            if _rc != 0 {
                let msg = if _out_error.is_null() {
                    format!("vtable.validate returned error code {}", _rc)
                } else {
                    // SAFETY: out_error was written by the callee as a valid NUL-terminated string.
                    let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                        .to_string_lossy()
                        .into_owned();
                    if let Some(free_fn) = vtable.free_string {
                        // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                        unsafe { free_fn(_out_error) };
                    }
                    msg
                };
                return Err(Box::from(msg));
            }
            Ok(())
        });
        tokio::task::spawn_blocking(move || _task.call())
            .await
            .map_err(|e| xberg::XbergError::Other(format!("spawn_blocking failed in validate: {}", e)))?
            .map_err(|e: Box<dyn std::error::Error + Send + Sync>| xberg::XbergError::Other(e.to_string()))
    }

    fn should_validate(&self, _result: &xberg::ExtractionResult, _config: &xberg::ExtractionConfig) -> bool {
        let Some(fp) = self.vtable.should_validate else {
            return false;
        };
        let __result_json = serde_json::to_string(&_result).unwrap_or_default();
        let __result_cs = match std::ffi::CString::new(__result_json) {
            Ok(s) => s,
            Err(_) => {
                return false;
            }
        };
        let _result_ptr = __result_cs.as_ptr();
        let __config_json = serde_json::to_string(&_config).unwrap_or_default();
        let __config_cs = match std::ffi::CString::new(__config_json) {
            Ok(s) => s,
            Err(_) => {
                return false;
            }
        };
        let _config_ptr = __config_cs.as_ptr();
        // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
        // user_data validity is the caller's responsibility (documented in the vtable API).
        let _rc = unsafe { fp(self.user_data, _result_ptr, _config_ptr) };
        _rc != 0
    }

    fn priority(&self) -> i32 {
        let Some(fp) = self.vtable.priority else {
            return 0;
        };
        // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
        // user_data validity is the caller's responsibility (documented in the vtable API).
        unsafe { fp(self.user_data) }
    }
}

/// Register a C plugin implementing `Validator` via a vtable.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `vtable`: vtable with function pointers implementing the trait.
/// - `user_data`: opaque pointer forwarded to every vtable function.
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// All function pointers in `vtable` must remain valid until the plugin is
/// unregistered. `user_data` must be safe to use from any thread that calls
/// into the plugin.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_register_validator(
    name: *const std::ffi::c_char,
    vtable: *const XbergValidatorVTable,
    user_data: *const std::ffi::c_void,
    out_error: *mut *mut std::ffi::c_char,
) -> i32 {
    if name.is_null() {
        ffi_set_out_error(out_error, "name must not be null");
        return 1;
    }
    if vtable.is_null() {
        ffi_set_out_error(out_error, "vtable must not be null");
        return 1;
    }
    let vtable_ref = &*vtable;
    if vtable_ref.free_string.is_none() {
        ffi_set_out_error(out_error, "vtable.free_string must not be null");
        return 1;
    }
    if vtable_ref.validate.is_none() {
        ffi_set_out_error(out_error, "vtable.validate must not be null");
        return 1;
    }

    // SAFETY: name is non-null (checked above); it points to a valid C string.
    let plugin_name = match unsafe { std::ffi::CStr::from_ptr(name) }.to_str() {
        Ok(s) => s.to_owned(),
        Err(_) => {
            ffi_set_out_error(out_error, "name is not valid UTF-8");
            return 1;
        }
    };

    // SAFETY: vtable pointer and user_data validity is the caller's responsibility.
    let bridge = unsafe { XbergValidatorBridge::new(plugin_name, *vtable_ref, user_data) };
    let arc: Arc<dyn xberg::Validator> = Arc::new(bridge);

    let registry = xberg::plugins::registry::get_validator_registry();
    let mut registry = registry.write();

    if let Err(e) = registry.register(arc) {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// Unregister a previously registered C plugin by name.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// `name` must point to a valid null-terminated C string.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_unregister_validator(
    name: *const std::ffi::c_char,
    out_error: *mut *mut std::ffi::c_char,
) -> i32 {
    if name.is_null() {
        ffi_set_out_error(out_error, "name must not be null");
        return 1;
    }
    // SAFETY: name is non-null (checked above); it points to a valid C string.
    let plugin_name = match unsafe { std::ffi::CStr::from_ptr(name) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            ffi_set_out_error(out_error, "name is not valid UTF-8");
            return 1;
        }
    };

    let registry = xberg::plugins::registry::get_validator_registry();
    let mut registry = registry.write();
    if let Err(e) = registry.remove(plugin_name) {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// Remove all registered C plugins of this trait.
///
/// # Parameters
///
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// `out_error` may be null. When non-null, the caller owns the resulting string
/// and must free it with `xberg_free_string`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_clear_validator(out_error: *mut *mut std::ffi::c_char) -> i32 {
    let registry = xberg::plugins::registry::get_validator_registry();
    let mut registry = registry.write();
    if let Err(e) = registry.clear() {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// VTable for C plugin bridges implementing the `EmbeddingBackend` trait.
///
/// # Safety
///
/// All function pointers must be valid for the lifetime of any bridge created from
/// this vtable.  `free_user_data`, when non-null, is called once with `user_data`
/// when the bridge is dropped.
#[derive(Copy, Clone)]
#[repr(C)]
pub struct XbergEmbeddingBackendVTable {
    /// Return a null-terminated UTF-8 name string into `out_name`; return 0 on success.
    pub name_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_name: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Return a null-terminated UTF-8 version string into `out_version`; return 0 on success.
    pub version_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_version: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Initialise the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub initialize_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Shut down the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub shutdown_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Embedding vector dimension. Must be `> 0` and must match the length of
    /// every vector returned by `embed`.
    pub dimensions: Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void) -> usize>,
    /// Embed a batch of texts, returning one vector per input in order.
    ///
    /// # Errors
    ///
    /// Implementations should return `Plugin` for
    /// backend-specific failures. The dispatcher layers its own validation
    /// (length, per-vector dimension) on top.
    pub embed: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            texts: *const std::ffi::c_char,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional string destructor: called for strings returned by vtable callbacks.
    pub free_string: Option<unsafe extern "C" fn(*mut std::ffi::c_char)>,
    /// Optional destructor: called once with `user_data` when the bridge is dropped.
    pub free_user_data: Option<unsafe extern "C" fn(*mut std::ffi::c_void)>,
}

// SAFETY: all fields are function pointers and free_user_data, which are Send + Sync.
unsafe impl Send for XbergEmbeddingBackendVTable {}
