/// VTable for C plugin bridges implementing the `RerankerBackend` trait.
///
/// # Safety
///
/// All function pointers must be valid for the lifetime of any bridge created from
/// this vtable.  `free_user_data`, when non-null, is called once with `user_data`
/// when the bridge is dropped.
#[derive(Copy, Clone)]
#[repr(C)]
pub struct XbergRerankerBackendVTable {
    /// Return a null-terminated UTF-8 name string into `out_name`; return 0 on success.
    pub name_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_name: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Return a null-terminated UTF-8 version string into `out_version`; return 0 on success.
    pub version_fn: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            out_version: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Initialise the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub initialize_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Shut down the plugin; return 0 on success, non-zero on failure (error text in `out_error`).
    pub shutdown_fn:
        Option<unsafe extern "C" fn(user_data: *const std::ffi::c_void, out_error: *mut *mut std::ffi::c_char) -> i32>,
    /// Score a list of documents against a query.
    ///
    /// Returns one raw logit per document in the same order as the input.
    /// The dispatcher applies sigmoid to convert to `[0, 1]` scores.
    ///
    /// # Errors
    ///
    /// Implementations should return `Plugin` for
    /// backend-specific failures. The dispatcher validates the returned length
    /// against `documents.len()` before sorting.
    pub rerank: Option<
        unsafe extern "C" fn(
            user_data: *const std::ffi::c_void,
            query: *const std::ffi::c_char,
            documents: *const std::ffi::c_char,
            out_result: *mut *mut std::ffi::c_char,
            out_error: *mut *mut std::ffi::c_char,
        ) -> i32,
    >,
    /// Optional string destructor: called for strings returned by vtable callbacks.
    pub free_string: Option<unsafe extern "C" fn(*mut std::ffi::c_char)>,
    /// Optional destructor: called once with `user_data` when the bridge is dropped.
    pub free_user_data: Option<unsafe extern "C" fn(*mut std::ffi::c_void)>,
}

// SAFETY: all fields are function pointers and free_user_data, which are Send + Sync.
unsafe impl Send for XbergRerankerBackendVTable {}
unsafe impl Sync for XbergRerankerBackendVTable {}

/// Rust-side bridge that holds a C vtable pointer and opaque `user_data`.
///
/// Implements `RerankerBackend` by forwarding calls through the vtable.
pub struct XbergRerankerBackendBridge {
    vtable: XbergRerankerBackendVTable,
    user_data: *const std::ffi::c_void,
    cached_name: String,
    cached_version: String,
}

impl std::fmt::Debug for XbergRerankerBackendBridge {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("XbergRerankerBackendBridge")
            .field("cached_name", &self.cached_name)
            .field("cached_version", &self.cached_version)
            .finish_non_exhaustive()
    }
}

// SAFETY: The caller is responsible for ensuring `user_data` is safe to send across
// thread boundaries. This is documented in `XbergRerankerBackendVTable` and the registration function.
unsafe impl Send for XbergRerankerBackendBridge {}
unsafe impl Sync for XbergRerankerBackendBridge {}

impl Drop for XbergRerankerBackendBridge {
    fn drop(&mut self) {
        if let Some(free_fn) = self.vtable.free_user_data {
            // SAFETY: free_fn is a valid function pointer; user_data is the pointer
            // originally provided at registration. Called exactly once here.
            unsafe { free_fn(self.user_data as *mut std::ffi::c_void) }
        }
    }
}

impl XbergRerankerBackendBridge {
    /// Create a new bridge from a vtable and opaque user_data pointer.
    ///
    /// # Safety
    ///
    /// `vtable` must remain valid for the lifetime of the returned bridge.
    /// `user_data` must be valid for any thread that calls methods on this bridge.
    /// All required fn pointers in `vtable` must be non-null.
    pub unsafe fn new(name: String, vtable: XbergRerankerBackendVTable, user_data: *const std::ffi::c_void) -> Self {
        Self {
            vtable,
            user_data,
            cached_name: name,
            cached_version: String::new(),
        }
    }
}

impl xberg::plugins::Plugin for XbergRerankerBackendBridge {
    fn name(&self) -> &str {
        &self.cached_name
    }
    fn version(&self) -> String {
        let Some(fp) = self.vtable.version_fn else {
            return String::new();
        };
        let mut _out: *mut std::ffi::c_char = std::ptr::null_mut();
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out, &mut _out_error) };
        if rc != 0 {
            if !_out_error.is_null() {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let _ = unsafe { std::ffi::CStr::from_ptr(_out_error) }.to_string_lossy();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
            }
            return self.cached_version.clone();
        }
        if _out.is_null() {
            return self.cached_version.clone();
        }
        // SAFETY: _out is a callee-allocated NUL-terminated string.
        let version = unsafe { std::ffi::CStr::from_ptr(_out) }.to_string_lossy().into_owned();
        if let Some(free_fn) = self.vtable.free_string {
            // SAFETY: free_fn is the vtable-provided destructor for callback strings.
            unsafe { free_fn(_out) };
        }
        version
    }
    fn initialize(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.initialize_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("initialize returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
    fn shutdown(&self) -> std::result::Result<(), xberg::XbergError> {
        let Some(fp) = self.vtable.shutdown_fn else {
            return Ok(());
        };
        let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
        // SAFETY: fp is valid; user_data validity is the caller's responsibility.
        let rc = unsafe { fp(self.user_data, &mut _out_error) };
        if rc != 0 {
            let msg = if _out_error.is_null() {
                format!("shutdown returned {}", rc)
            } else {
                // SAFETY: _out_error is a callee-allocated NUL-terminated string.
                let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                    .to_string_lossy()
                    .into_owned();
                if let Some(free_fn) = self.vtable.free_string {
                    // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                    unsafe { free_fn(_out_error) };
                }
                msg
            };
            return Err(xberg::XbergError::Plugin {
                message: msg,
                plugin_name: String::new(),
            });
        }
        Ok(())
    }
}

#[async_trait::async_trait]
impl xberg::RerankerBackend for XbergRerankerBackendBridge {
    async fn rerank(&self, query: String, documents: Vec<String>) -> std::result::Result<Vec<f32>, xberg::XbergError> {
        struct _SendFn<F>(F);
        // SAFETY: caller guarantees vtable fn pointers and user_data are valid across threads.
        unsafe impl<F> Send for _SendFn<F> {}
        impl<F: FnOnce() -> R, R> _SendFn<F> {
            fn call(self) -> R {
                (self.0)()
            }
        }

        let _cached_name = self.cached_name.clone();
        let vtable = self.vtable;
        let user_data = self.user_data;
        let query = query.clone();
        let documents = documents.clone();

        let _task = _SendFn(move || {
            // Inline the sync body:
            let Some(fp) = vtable.rerank else {
                return Err(Box::from("vtable.rerank is null — bridge not initialised"));
            };
            let _query_cs = match std::ffi::CString::new(query.as_str()) {
                Ok(s) => s,
                Err(_) => {
                    return Err(Box::from("nul byte in param query"));
                }
            };
            let query_ptr = _query_cs.as_ptr();
            let _documents_json = serde_json::to_string(&documents).unwrap_or_default();
            let _documents_cs = match std::ffi::CString::new(_documents_json) {
                Ok(s) => s,
                Err(_) => {
                    return Err(Box::from("nul byte in serialized param documents"));
                }
            };
            let documents_ptr = _documents_cs.as_ptr();
            let mut _out_result: *mut std::ffi::c_char = std::ptr::null_mut();
            let mut _out_error: *mut std::ffi::c_char = std::ptr::null_mut();
            // SAFETY: fp is a valid non-null function pointer; all temporaries outlive this call;
            // user_data validity is the caller's responsibility (documented in the vtable API).
            let _rc = unsafe { fp(user_data, query_ptr, documents_ptr, &mut _out_result, &mut _out_error) };
            if _rc != 0 {
                let msg = if _out_error.is_null() {
                    format!("vtable.rerank returned error code {}", _rc)
                } else {
                    // SAFETY: out_error was written by the callee as a valid NUL-terminated string.
                    let msg = unsafe { std::ffi::CStr::from_ptr(_out_error) }
                        .to_string_lossy()
                        .into_owned();
                    if let Some(free_fn) = vtable.free_string {
                        // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                        unsafe { free_fn(_out_error) };
                    }
                    msg
                };
                return Err(Box::from(msg));
            }
            if _out_result.is_null() {
                return Err(Box::from("vtable.rerank returned null out_result"));
            }
            // SAFETY: out_result was written by the callee as a valid NUL-terminated string.
            let json = unsafe { std::ffi::CStr::from_ptr(_out_result) }
                .to_string_lossy()
                .into_owned();
            if let Some(free_fn) = vtable.free_string {
                // SAFETY: free_fn is the vtable-provided destructor for callback strings.
                unsafe { free_fn(_out_result) };
            }
            serde_json::from_str::<Vec<f32>>(&json)
                .map_err(|e| Box::from(e.to_string()) as Box<dyn std::error::Error + Send + Sync>)
        });
        tokio::task::spawn_blocking(move || _task.call())
            .await
            .map_err(|e| xberg::XbergError::Other(format!("spawn_blocking failed in rerank: {}", e)))?
            .map_err(|e: Box<dyn std::error::Error + Send + Sync>| xberg::XbergError::Other(e.to_string()))
    }
}

/// Register a C plugin implementing `RerankerBackend` via a vtable.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `vtable`: vtable with function pointers implementing the trait.
/// - `user_data`: opaque pointer forwarded to every vtable function.
/// - `out_error`: receives a heap-allocated error string on failure.
///
/// # Safety
///
/// All function pointers in `vtable` must remain valid until the plugin is
/// unregistered. `user_data` must be safe to use from any thread that calls
/// into the plugin.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn xberg_register_reranker_backend(
    name: *const std::ffi::c_char,
    vtable: *const XbergRerankerBackendVTable,
    user_data: *const std::ffi::c_void,
    out_error: *mut *mut std::ffi::c_char,
) -> i32 {
    if name.is_null() {
        ffi_set_out_error(out_error, "name must not be null");
        return 1;
    }
    if vtable.is_null() {
        ffi_set_out_error(out_error, "vtable must not be null");
        return 1;
    }
    let vtable_ref = &*vtable;
    if vtable_ref.free_string.is_none() {
        ffi_set_out_error(out_error, "vtable.free_string must not be null");
        return 1;
    }
    if vtable_ref.rerank.is_none() {
        ffi_set_out_error(out_error, "vtable.rerank must not be null");
        return 1;
    }

    // SAFETY: name is non-null (checked above); it points to a valid C string.
    let plugin_name = match unsafe { std::ffi::CStr::from_ptr(name) }.to_str() {
        Ok(s) => s.to_owned(),
        Err(_) => {
            ffi_set_out_error(out_error, "name is not valid UTF-8");
            return 1;
        }
    };

    // SAFETY: vtable pointer and user_data validity is the caller's responsibility.
    let bridge = unsafe { XbergRerankerBackendBridge::new(plugin_name, *vtable_ref, user_data) };
    let arc: Arc<dyn xberg::RerankerBackend> = Arc::new(bridge);

    let registry = xberg::plugins::registry::get_reranker_backend_registry();
    let mut registry = registry.write();

    if let Err(e) = registry.register(arc) {
        ffi_set_out_error(out_error, &e.to_string());
        return 1;
    }
    0
}

/// Unregister a previously registered C plugin by name.
///
/// # Parameters
///
/// - `name`: null-terminated UTF-8 plugin name. Must not be null.
/// - `out_error`: receives a heap-allocated error string on failure.
